#include <stdio.h>
#include <stdlib.h>
#include <dirent.h>
#include <sys/stat.h>
#include <unistd.h>

int main() {
    // Create directory
    mkdir("test_dir", 0755);
    printf("Directory created\n");

    // Create file in directory
    FILE *f = fopen("test_dir/file.txt", "w");
    fprintf(f, "Hello");
    fclose(f);

    // List directory contents
    DIR *dir = opendir("test_dir");
    struct dirent *entry;

    printf("\nDirectory contents:\n");
    while ((entry = readdir(dir)) != NULL) {
        printf("  %s (type: %d)\n", entry->d_name, entry->d_type);
    }
    closedir(dir);

    // Create hard link
    link("test_dir/file.txt", "test_dir/hardlink.txt");
    printf("\nHard link created\n");

    // Create symbolic link
    symlink("file.txt", "test_dir/softlink.txt");
    printf("Symbolic link created\n");

    // Check link count
    struct stat st;
    stat("test_dir/file.txt", &st);
    printf("Link count: %d\n", (int)st.st_nlink);

    // Get current directory
    char cwd[256];
    getcwd(cwd, sizeof(cwd));
    printf("\nCurrent directory: %s\n", cwd);

    // Cleanup
    unlink("test_dir/softlink.txt");
    unlink("test_dir/hardlink.txt");
    unlink("test_dir/file.txt");
    rmdir("test_dir");

    return 0;
}

