import java.io.*;
import java.nio.file.*;

public class DirectoryOps {
    public static void main(String[] args) throws IOException {
        Path testDir = Paths.get("test_dir");
        Path subDir = testDir.resolve("subdir");

        // Create directories
        Files.createDirectories(subDir);
        System.out.println("Directories created");

        // Create file
        Path file = testDir.resolve("file.txt");
        Files.write(file, "Hello".getBytes());

        // List directory
        System.out.println("\nDirectory contents:");
        try (DirectoryStream<Path> stream = Files.newDirectoryStream(testDir)) {
            for (Path entry : stream) {
                String type = Files.isDirectory(entry) ? "dir" : "file";
                System.out.println("  " + entry.getFileName() + " (" + type + ")");
            }
        }

        // Walk directory tree
        System.out.println("\nWalking tree:");
        Files.walk(testDir).forEach(p -> {
            int depth = p.getNameCount() - testDir.getNameCount();
            String indent = "  ".repeat(depth);
            System.out.println(indent + p.getFileName());
        });

        // Create symbolic link (may require admin on Windows)
        try {
            Path symlink = testDir.resolve("symlink.txt");
            Files.createSymbolicLink(symlink, Paths.get("file.txt"));
            System.out.println("\nSymbolic link created");
        } catch (Exception e) {
            System.out.println("Symlink error: " + e.getMessage());
        }

        // Paths
        System.out.println("\nAbsolute: " + file.toAbsolutePath());
        System.out.println("Current: " + Paths.get("").toAbsolutePath());

        // Cleanup
        Files.walk(testDir)
             .sorted((a, b) -> -a.compareTo(b))
             .forEach(p -> { try { Files.delete(p); } catch (Exception e) {} });
    }
}
